export type BindType = {
    type: "import";
    path: string;
} | {
    type: "new";
    schema?: {
        name: string;
        type: string;
    }[];
} | {
    type: "raw";
    raw_type: string;
};
export interface Binding {
    ident: string;
    array: boolean;
    objectType: string;
    type: BindType;
    isField: boolean;
}
export interface Field {
    ident: string;
}
export interface ObjectField {
    objectIdent: string;
    field: string;
}
export interface TableFunction {
    ident: string;
    fields: string[];
}
export interface ForLoop {
    innerIdent: string;
    ident: string;
    latexToIterate: string;
}
export interface IfStatement {
    ident: string;
    condition: string;
    trueLatex: string;
    falseLatex?: string;
}
export interface TypeData {
    bindings: Binding[];
}
